css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #070b18; color: white; }
.layout { display: flex; min-height: 100vh; }
aside { width: 240px; background: #0d1117; border-right: 1px solid rgba(255,255,255,0.07); padding: 24px 14px; flex-shrink: 0; display: flex; flex-direction: column; }
.brand { font-size: 20px; font-weight: 800; padding: 0 10px; margin-bottom: 28px; }
nav { display: flex; flex-direction: column; gap: 4px; }
.nav-item { display: block; padding: 12px 14px; border-radius: 10px; color: #6b7280; font-size: 14px; cursor: pointer; transition: all 0.2s; } .nav-item:hover { background: rgba(255,255,255,0.05); color: white; } .nav-item.active { background: rgba(59,130,246,0.15); color: #60a5fa; font-weight: 600; }
main { flex: 1; padding: 24px; overflow-y: auto; }
.topbar { display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px; }
.topbar h1 { font-size: 24px; font-weight: 800; } .topbar p { color: #6b7280; font-size: 13px; }
.add-btn { padding: 12px 20px; border-radius: 12px; border: none; background: #3b82f6; color: white; font-weight: 700; font-size: 14px; cursor: pointer; }
.kpi-row { display: grid; grid-template-columns: repeat(4,1fr); gap: 14px; margin-bottom: 20px; }
.kpi-card { background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.07); border-radius: 14px; padding: 16px; display: flex; gap: 14px; align-items: center; }
.kpi-icon { width: 44px; height: 44px; border-radius: 12px; display: flex; align-items: center; justify-content: center; font-size: 18px; flex-shrink: 0; } .blue { background: rgba(59,130,246,0.2); } .green { background: rgba(34,197,94,0.2); } .yellow { background: rgba(234,179,8,0.2); } .purple { background: rgba(139,92,246,0.2); }
.kpi-label { font-size: 11px; color: #6b7280; margin-bottom: 4px; } .kpi-val { font-size: 20px; font-weight: 800; margin-bottom: 2px; } .kpi-change { font-size: 11px; font-weight: 600; } .up { color: #22c55e; }
.content-grid { display: grid; grid-template-columns: 1.2fr 1fr; gap: 16px; margin-bottom: 16px; }
.pipeline-card, .activity-card { background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.07); border-radius: 14px; padding: 20px; }
.pipeline-card h3, .activity-card h3 { font-size: 15px; font-weight: 700; margin-bottom: 20px; }
.pipeline { display: flex; flex-direction: column; gap: 14px; }
.stage-header { display: flex; justify-content: space-between; font-size: 13px; margin-bottom: 6px; } .stage-count { color: #6b7280; }
.stage-bar { height: 6px; background: rgba(255,255,255,0.08); border-radius: 3px; margin-bottom: 4px; } .stage-bar div { height: 100%; border-radius: 3px; }
.stage-val { font-size: 12px; color: #6b7280; text-align: right; }
.activity-list { display: flex; flex-direction: column; gap: 0; }
.act-item { display: flex; align-items: center; gap: 12px; padding: 12px 0; border-bottom: 1px solid rgba(255,255,255,0.05); }
.act-icon { font-size: 18px; width: 36px; height: 36px; border-radius: 10px; background: rgba(255,255,255,0.06); display: flex; align-items: center; justify-content: center; flex-shrink: 0; }
.act-info { flex: 1; } .act-info strong { display: block; font-size: 13px; } .act-info small { color: #6b7280; font-size: 11px; }
.act-badge { padding: 3px 8px; border-radius: 6px; font-size: 11px; font-weight: 700; white-space: nowrap; } .success { background: rgba(34,197,94,0.15); color: #22c55e; } .pending { background: rgba(234,179,8,0.15); color: #eab308; } .upcoming { background: rgba(59,130,246,0.15); color: #60a5fa; }
.customers-card { background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.07); border-radius: 14px; padding: 20px; }
.cc-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 16px; } .cc-header h3 { font-size: 15px; font-weight: 700; }
.search-input { height: 36px; border-radius: 10px; border: 1px solid rgba(255,255,255,0.1); background: rgba(255,255,255,0.05); color: white; padding: 0 14px; font-size: 13px; outline: none; width: 220px; }
table { width: 100%; border-collapse: collapse; } th { text-align: left; font-size: 12px; color: #6b7280; font-weight: 600; padding: 0 0 10px; border-bottom: 1px solid rgba(255,255,255,0.07); } td { padding: 12px 0; font-size: 13px; border-bottom: 1px solid rgba(255,255,255,0.04); }
.status-badge { padding: 3px 8px; border-radius: 6px; font-size: 11px; font-weight: 700; } .active { background: rgba(34,197,94,0.15); color: #22c55e; } .inactive { background: rgba(107,114,128,0.15); color: #9ca3af; } .vip { background: rgba(234,179,8,0.15); color: #eab308; }

