const customers = [
  {name:'Ahmet Yılmaz', company:'TechVision A.Ş.', status:'vip', val:'₺240K', contact:'Bugün'},
  {name:'Ayşe Kaya', company:'StartupX Ltd.', status:'active', val:'₺85K', contact:'Dün'},
  {name:'Mehmet Demir', company:'InnovateLab', status:'active', val:'₺120K', contact:'2 gün önce'},
  {name:'Fatma Şahin', company:'FutureTech', status:'inactive', val:'₺45K', contact:'1 hafta önce'},
  {name:'Ali Rıza', company:'CryptoHub', status:'vip', val:'₺380K', contact:'3 gün önce'}
];
function renderCustomers(data) {
  document.getElementById('customers-body').innerHTML = data.map(c => `
    <tr>
      <td><strong>${c.name}</strong></td>
      <td><span style='color:#9ca3af'>${c.company}</span></td>
      <td><span class='status-badge ${c.status}'>${c.status === 'vip' ? '⭐ VIP' : c.status === 'active' ? 'Aktif' : 'Pasif'}</span></td>
      <td><strong style='color:#22c55e'>${c.val}</strong></td>
      <td><span style='color:#6b7280'>${c.contact}</span></td>
    </tr>
  `).join('');
}
function searchCustomers(q) { renderCustomers(customers.filter(c => c.name.toLowerCase().includes(q.toLowerCase()) || c.company.toLowerCase().includes(q.toLowerCase()))); }
document.querySelectorAll('.nav-item').forEach(item => { item.addEventListener('click', function() { document.querySelectorAll('.nav-item').forEach(i => i.classList.remove('active')); this.classList.add('active'); }); });
renderCustomers(customers);
